select id, name, phone, images, password, fans_counts, follower_counts, money, address, status, shop_id, create_time, update_time from user


        and id = #{id}


        and name like concat('%', #{name}, '%')


        and phone = #{phone}


        and password = #{password}


        and status = #{status}


        and shop_id = #{shopId}


        and create_time = #{createTime}


        and update_time = #{updateTime}
